(574, '3696', '2025-10-04', '9AM-11AM', 'Training classes for the students', 'Working on the javascript on the training for the students . Making note of  the some of the Imprortant topics on the javascript ', NULL, NULL, NULL, 'BHARATH SIMHA REDDY V '),
(575, '4196', '2025-10-04', '9AM-11AM', 'Database & JDBC', '\r\nImplemented Insert operation using JDBC to add new records into the database.', NULL, NULL, NULL, 'Jayshree'),
(576, '4196', '2025-10-04', '11AM-1PM', 'Database & JDBC', 'Implemented Update operation to modify existing data in the database.', NULL, NULL, NULL, 'Jayshree'),
(577, '4196', '2025-10-04', '4PM-6PM', 'Database & JDBC', 'Implemented CRUD (Create, Read, Update, Delete) operations in Java using JDBC.\r\nConnected Java application to a relational database (e.g., PostgreSQL/MySQL).\r\nCreated necessary database tables and performed insert, update, delete, and select queries using PreparedStatement.\r\nTested all CRUD functionalities through console-based or Java program execution.', NULL, NULL, NULL, 'Jayshree'),
(578, '4194', '2025-10-06', '9AM-11AM', 'Spring Boot CRUD Operations â Project Setup & Create Operation', 'Set up a new Spring Boot project using Spring Initializr.\r\n\r\nAdd dependencies:\r\n\r\nspring-boot-starter-web\r\n\r\nspring-boot-starter-data-jpa\r\n\r\nmysql-connector-j\r\n\r\nConfigure application.properties for database connection.\r\n\r\nCreate:\r\n\r\nEntity class (e.g., VenueEntity)\r\n\r\nRepository interface\r\n\r\nImplement the Create (POST) API to insert data into the database.\r\n\r\nTest Create API in Postman.', NULL, NULL, NULL, 'Muskan'),
(579, '4194', '2025-10-06', '11AM-1PM', 'Task Category: Spring Boot CRUD Operations â Read Operation', 'Implement Read (GET) APIs:\r\n\r\nGET /entities ? fetch all records\r\n\r\nGET /entities/{id} ? fetch record by ID\r\n\r\nAdd service layer for better structure (Controller ? Service ? Repository).\r\n\r\nTest both endpoints using Postman.\r\n\r\nHandle ârecord not foundâ using custom exception.', NULL, NULL, NULL, 'Muskan'),
(580, '4194', '2025-10-06', '2PM-4PM', 'Spring Boot CRUD Operations â Update Operation', 'Implement Update (PUT) API to modify existing records.\r\n\r\nUse @PathVariable and @RequestBody correctly.\r\n\r\nAdd input validations using annotations like @NotNull, @Size.\r\n\r\nTest API with various inputs and error conditions.', NULL, NULL, NULL, 'Muskan'),
(581, '4194', '2025-10-06', '4PM-6PM', 'Spring Boot CRUD Operations â Delete Operation & Final Testing', 'Implement Delete (DELETE) API to remove records by ID.\r\n\r\nAdd a check for non-existing IDs.\r\n\r\nTest full CRUD cycle in Postman (Create ? Read ? Update ? Delete).\r\n\r\nPerform code cleanup and documentation.\r\n\r\nCommit final version to GitHub.', NULL, NULL, NULL, 'Muskan'),
(582, '4196', '2025-10-06', '11AM-1PM', 'Registration Form', 'A registration form is used to collect user details (like name, email, password, etc.) and store them in a database.', NULL, NULL, NULL, 'Jayshree'),
(583, '2744', '2025-10-07', '9AM-11AM', 'Data analyst', 'Learning new skills ', NULL, NULL, NULL, 'Pawan Kumar Yadav'),
(584, '4194', '2025-10-07', '9AM-11AM', 'Meeting with Senior', 'During this time slot, I had a meeting with my senior to present the progress of my project. I demonstrated the implementation of CRUD operations (Create, Read, Update, Delete) that I developed using Spring Boot.\r\n\r\nI explained the functionality of each operation, including how the API endpoints handle data interactions between the backend and the database. I also discussed the structure of the project â entities, repositories, services, and controllers â and how they are connected within the Spring Boot architecture.\r\n\r\nMy senior reviewed the project and provided valuable feedback and suggestions for improvement, such as optimizing certain service methods and enhancing validation logic. Overall, the meeting went well, and the CRUD module was successfully demonstrated.\r\n\r\nOutcome:\r\n\r\nSuccessfully showcased CRUD operations using Spring Boot.\r\n\r\nReceived feedback and improvement suggestions.\r\n\r\nNext step: Implement suggested improvements and prepare for the next review.', NULL, NULL, NULL, 'Muskan'),
(585, '4194', '2025-10-07', '11AM-1PM', 'Meeting with Senior', 'During this time slot, I had a meeting with my senior to present the progress of my project. I demonstrated the implementation of CRUD operations (Create, Read, Update, Delete) that I developed using Spring Boot.\r\n\r\nI explained the functionality of each operation, including how the API endpoints handle data interactions between the backend and the database. I also discussed the structure of the project â entities, repositories, services, and controllers â and how they are connected within the Spring Boot architecture.\r\n\r\nMy senior reviewed the project and provided valuable feedback and suggestions for improvement, such as optimizing certain service methods and enhancing validation logic. Overall, the meeting went well, and the CRUD module was successfully demonstrated.\r\n\r\nOutcome:\r\n\r\nSuccessfully showcased CRUD operations using Spring Boot.\r\n\r\nReceived feedback and improvement suggestions.\r\n\r\nNext step: Implement suggested improvements and prepare for the next review.', NULL, NULL, NULL, 'Muskan'),
(586, '2744', '2025-10-07', '11AM-1PM', 'Data', 'Improving skill', NULL, NULL, NULL, 'Pawan Kumar Yadav'),
(587, '4196', '2025-10-07', '11AM-1PM', 'login form', 'The login task is to allow users to access the system by validating their credentials (like email/username and password) stored in a database.', NULL, NULL, NULL, 'Jayshree'),
(588, '2789', '2025-10-07', '9AM-11AM', 'Project and training department ', 'Working in personal project ', NULL, NULL, NULL, '2789');
