(603, '4196', '2025-10-07', '9AM-11AM', 'CRUD Application with Spring Boot', 'Implemented Create (Insert) functionality to add new records into the database using Spring Boot and Spring Data JPA. And\r\nWorked on Update functionality to modify existing records through forms and backend API.', NULL, NULL, NULL, 'Jayshree'),
