INSERT INTO `work_report` (`id`, `emp_id`, `report_date`, `time_slot`, `task_category`, `task_details`, `shift_start`, `shift_end`, `email`, `name`) VALUES
(847, '3697', '2025-10-15', '2PM-4PM', 'Understanding JSP Directives', 'Learned about different JSP directives such as page, include, and taglib. Practiced using the include directive to reuse header and footer content across multiple JSP pages. Understood how page directives control page behavior and error handling.', NULL, NULL, NULL, 'Yandra Ravi Babu'),
(848, '4196', '2025-10-15', '4PM-6PM', 'Hitz Crafty Website â Registration Module Development', 'Designed and implemented the registration page (register.html) using Thymeleaf and styled it with Bootstrap CSS for a responsive and user-friendly interface. Tested the registration flow successfully with database integration.', NULL, NULL, NULL, 'Jayshree'),
(849, '4194', '2025-10-15', '9AM-11AM', 'JavaScript Conditional Statements', 'I studied decision-making statements in JavaScript, which allow the program to perform different actions based on different conditions.\r\n\r\nif statement: Executes a block of code only if a specific condition is true.\r\n\r\nelse if statement: Tests another condition if the first one is false.\r\n\r\nelse statement: Executes a block of code when none of the above conditions are true.', NULL, NULL, NULL, 'Muskan'),
(850, '4194', '2025-10-15', '11AM-1PM', 'JavaScript Loops', 'I learned how loops are used to repeat a block of code multiple times, which helps avoid writing repetitive code.\r\n\r\nfor loop: Runs code a fixed number of times.\r\n\r\nwhile loop: Runs code while a condition is true.\r\n\r\ndo-while loop: Runs code once, then checks the condition.\r\n\r\nfor...of loop: Used to iterate over arrays or strings.\r\n\r\nfor...in loop: Used to loop through object properties.', NULL, NULL, NULL, 'Muskan'),
(851, '4194', '2025-10-15', '2PM-4PM', 'JavaScript Core Functions', 'I explored basic JavaScript input/output and debugging functions:\r\n\r\nconsole.log() â Displays output or debugging information in the console.\r\n\r\nalert() â Shows messages in a pop-up alert box.\r\n\r\nprompt() â Asks the user to input data.', NULL, NULL, NULL, 'Muskan'),
(852, '4194', '2025-10-15', '4PM-6PM', 'Strings and Arrays', 'I studied strings (text data) and arrays (collections of data).\r\n\r\nString methods like .length, .toUpperCase(), .toLowerCase(), .slice(), .concat().\r\n\r\nArray methods like .push(), .pop(), .shift(), .unshift(), .indexOf(), .join().', NULL, NULL, NULL, 'Muskan'),
