(947, '3697', '2025-10-23', '9AM-11AM', 'Spring Framework Learning', 'Studied Spring Framework concepts including Spring Core, Spring MVC, and Spring Boot. Learned about dependency injection, bean configuration, and application context. Practiced creating a simple Spring Boot project with controllers and service layers.', NULL, NULL, NULL, 'Yandra Ravi Babu'),
(948, '3697', '2025-10-23', '11AM-1PM', 'Spring Framework Learning', 'Studied Spring Framework concepts including Spring Core, Spring MVC, and Spring Boot. Learned about dependency injection, bean configuration, and application context. Practiced creating a simple Spring Boot project with controllers and service layers.', NULL, NULL, NULL, 'Yandra Ravi Babu'),
