(976, '4194', '2025-10-25', '9AM-11AM', 'UI & Core Game Logic', 'Created initial HTML structure for the Rock-Paper-Scissors game (buttons for Rock / Paper / Scissors, result area, score display).\r\n\r\nImplemented core game logic in JavaScript: user choice, computer random choice, outcome determination (win/lose/draw).\r\n\r\nAdded basic CSS layout and responsive container to support mobile and desktop widths.\r\n', NULL, NULL, NULL, 'Muskan'),
(977, '4194', '2025-10-25', '11AM-1PM', 'Styling & Animations', 'Polished CSS: buttons styling, hover/active states, and a simple transition when result appears.\r\n\r\nAdded small animations for choice reveal (scale + fade) and result flash.\r\n\r\nImproved accessibility: added aria-labels to buttons and semantic roles for result area.\r\n', NULL, NULL, NULL, 'Muskan'),
(978, '4194', '2025-10-25', '2PM-4PM', 'Features & Testing', 'Implemented scoreboard (wins / losses / draws) and reset button.\r\n\r\nAdded persistent score using localStorage so scores survive refresh.\r\n\r\nManual testing across Chrome and Firefox; fixed logic edge-cases (ties and rapid clicks).\r\n\r\nWrote inline comments in JS for readability.', NULL, NULL, NULL, 'Muskan'),
(979, '4194', '2025-10-25', '4PM-6PM', 'Final polish & Deployment preperation', 'Fixed visual bugs (button alignment on small screens), optimized CSS for fewer repaint triggers.\r\n\r\nCreated README with game description, features, and instructions to run locally.\r\n\r\nPrepared files for deployment and tested index.html locally.\r\n\r\nNext steps: push to GitHub Pages or Netlify and add unit tests for game logic.', NULL, NULL, NULL, 'Muskan'),
