(985, '3697', '2025-10-27', '9AM-11AM', 'Learning the concepts of springboot', 'Studied the core concepts of Spring Boot, including project structure, auto-configuration, and dependency management. Explored how to create and run a Spring Boot application using SpringApplication.run(). Learned about annotations like @SpringBootApplication, @RestController, and @RequestMapping.', NULL, NULL, NULL, 'Yandra Ravi Babu'),
