(1002, '4196', '2025-10-28', '9AM-11AM', 'Hitz Crafty Project â Backend Setup in Spring Boot & Frontend Shift to VS Code', 'During this time, I started by setting up the backend project structure in Spring Boot using Spring Initializr. I configured all required dependencies such as Spring Web, Spring Data JPA, and MySQL Driver for backend development. I also created the project package structure (controller, service, repository, entity) and verified the project build successfully in STS (Spring Tool Suite).', NULL, NULL, NULL, 'Jayshree'),
(1003, '4139', '2025-10-28', '9AM-11AM', '2 Post On LinkedIn', 'Do two LinkedIn post of Salesforce Cloud Master Course ', NULL, NULL, NULL, 'Subhajit Ghosh'),
(1004, '4196', '2025-10-28', '11AM-1PM', 'Hitz Crafty Project â Backend Setup in Spring Boot & Frontend Shift to VS Code', 'In this session, I worked on configuring the database connection in the application.properties file. I provided the database name, username, and password to connect MySQL with the backend. I also created an Entity class for the user module and mapped it with database fields using JPA annotations. The database connection was tested and confirmed successfully.', NULL, NULL, NULL, 'Jayshree'),
(1005, '4194', '2025-10-28', '9AM-11AM', 'JavaScript Fundamentals â Object-Oriented Programming', 'Studied the concept of Classes and Objects in JavaScript.\r\n\r\nLearned how to define classes, create object instances, and use constructors and methods effectively.\r\n\r\nPracticed multiple coding examples to understand object behavior, encapsulation, and reusability in JavaScript.', NULL, NULL, NULL, 'Muskan');
INSERT INTO `work_report` (`id`, `emp_id`, `report_date`, `time_slot`, `task_category`, `task_details`, `shift_start`, `shift_end`, `email`, `name`) VALUES
(1006, '4194', '2025-10-28', '11AM-1PM', 'Advanced JavaScript Concepts', 'Studied callback functions and their role in handling asynchronous operations.\r\n\r\nImplemented practical examples to understand how callbacks are used for event handling and timed execution.\r\n\r\nExplored Promises and how they simplify asynchronous programming compared to callbacks.\r\n\r\nWrote hands-on examples using .then() and .catch() for promise resolution and error handling.', NULL, NULL, NULL, 'Muskan'),
(1007, '4194', '2025-10-28', '2PM-4PM', 'Modern Asynchronous JavaScript', 'Learned about async and await keywords and how they make asynchronous code easier to read and maintain.\r\n\r\nCompared async/await with Promises to understand their relationship and advantages.\r\n\r\nImplemented real-time examples converting Promises into async/await syntax for better code clarity.', NULL, NULL, NULL, 'Muskan'),
(1008, '4194', '2025-10-28', '4PM-6PM', 'API Integration in JavaScript', 'Started learning how to fetch APIs using JavaScript.\r\n\r\nStudied the Fetch API method for sending HTTP requests and receiving responses.\r\n\r\nPracticed fetching data from a sample public API and displayed it dynamically on a webpage.\r\n\r\nUnderstood the importance of error handling and response parsing (JSON format).', NULL, NULL, NULL, 'Muskan'),
(1009, '4196', '2025-10-28', '2PM-4PM', 'Hitz Crafty Project â Backend Setup in Spring Boot & Frontend Shift to VS Code', 'I focused on building the repository and service layers. The Repository (DAO) was created to handle CRUD operations, while the Service and Service Implementation layers were written to handle business logic. I also worked on the Controller layer to define endpoints for registration and login. All backend functionalities were tested using Postman to ensure correct data flow between frontend and database.', NULL, NULL, NULL, 'Jayshree'),
(1010, '4196', '2025-10-29', '9AM-11AM', 'Hitz Crafty Project â Backend Development in Spring Boot & Frontend Setup in VS Code', 'the day by setting up the backend environment in Spring Boot using Spring Initializr. I added essential dependencies like Spring Web, Spring Data JPA, and MySQL Driver for database integration. After that, I created a proper project structure with packages such as entity, repository, service, and controller, ensuring that the application compiled and ran successfully in Spring Tool Suite (STS).', NULL, NULL, NULL, 'Jayshree'),
(1011, '4196', '2025-10-29', '11AM-1PM', 'Hitz Crafty Project â Backend Development in Spring Boot & Frontend Setup in VS Code', ' I configured the database connection in the application.properties file by providing the database name, username, and password for MySQL connectivity. I then created the Entity class to represent the product and user data, mapping fields with JPA annotations. I also tested the database connection to make sure data was being stored and retrieved correctly.', NULL, NULL, NULL, 'Jayshree'),
(1012, '3697', '2025-10-29', '9AM-11AM', 'Spring Framework Learning', 'Studied the core concepts of Spring Boot, including project structure, auto-configuration, and dependency management. Explored how to create and run a Spring Boot application using SpringApplication.run(). Learned about annotations like @SpringBootApplication, @RestController, and @RequestMapping.', NULL, NULL, NULL, 'Yandra Ravi Babu'),
(1013, '3697', '2025-10-29', '11AM-1PM', 'Spring Framework Learning', 'Studied the core concepts of Spring Boot, including project structure, auto-configuration, and dependency management. Explored how to create and run a Spring Boot application using SpringApplication.run(). Learned about annotations like @SpringBootApplication, @RestController, and @RequestMapping.', NULL, NULL, NULL, 'Yandra Ravi Babu'),
(1014, '3697', '2025-10-29', '2PM-4PM', 'Spring Framework Learning', 'Studied the core concepts of Spring Boot, including project structure, auto-configuration, and dependency management. Explored how to create and run a Spring Boot application using SpringApplication.run(). Learned about annotations like @SpringBootApplication, @RestController, and @RequestMapping.', NULL, NULL, NULL, 'Yandra Ravi Babu'),
(1015, '4196', '2025-10-29', '2PM-4PM', 'Hitz Crafty Project â Backend Development in Spring Boot & Frontend Setup in VS Code', 'I focused on building the Repository, Service, and Controller layers of the backend. The Repository handled CRUD operations, while the Service and Service Implementation classes were written to manage the business logic. I then created RESTful API endpoints in the Controller to handle data requests such as product creation, fetching, updating, and deletion. Each API was tested using Postman to ensure the backend was functioning correctly.', NULL, NULL, NULL, 'Jayshree'),
