(1243, '4194', '2025-11-19', '9AM-11AM', 'JavaScript Fundamentals: OOP', 'Studied the concepts of Classes and Objects in JavaScript.\r\n\r\nLearned how to define classes, initialize objects, and use constructors and methods.\r\n\r\nPracticed multiple examples to understand object behavior, encapsulation, and code reusability.', NULL, NULL, NULL, 'Muskan'),
