(1435, '4196', '2025-12-15', '9AM-11AM', 'React (Getting Started & Basics)', 'Installed Node.js & npm (verified versions)\r\nCreated React app using:\r\ncreate-react-app or Vite\r\nRan the project and verified it loads in browser\r\nCleaned default files (logo, sample CSS, unused code)\r\nUnderstood React folder structure:\r\nsrc\r\ncomponents\r\nApp.jsx\r\nindex.js', NULL, NULL, NULL, 'Jayshree'),
(1436, '4196', '2025-12-15', '11AM-1PM', 'React (Getting Started & Basics)', 'Learned JSX syntax\r\nCreated first functional component\r\nUsed export and import\r\nAdded basic UI using JSX\r\nUnderstood difference between HTML vs JSX\r\nUsed className, fragments, and props basics', NULL, NULL, NULL, 'Jayshree'),
(1437, '4196', '2025-12-15', '2PM-4PM', 'React (Getting Started & Basics)', 'Learned useState hook\r\nImplemented:\r\nCounter app (increment / decrement)\r\nButton click events\r\nUnderstood state updates and re-rendering\r\nPracticed passing state between components', NULL, NULL, NULL, 'Jayshree'),
(1438, '4196', '2025-12-15', '4PM-6PM', 'React (Getting Started & Basics)', 'Created a small React feature:\r\nToDo list / Counter / Simple form\r\nPracticed:\r\nConditional rendering\r\nEvent handling\r\nFixed errors and revised all topics\r\nUnderstood React workflow clearly', NULL, NULL, NULL, 'Jayshree'),
(1439, '4196', '2025-12-16', '9AM-11AM', 'React (Props, useEffect, API Call, Routing)', 'Learned what props are and why they are used\r\nPassed data from parent component ? child component\r\nUsed props to display dynamic content\r\nPracticed reusable components using props\r\nUnderstood default props and destructuring props', NULL, NULL, NULL, 'Jayshree'),
(1440, '4196', '2025-12-16', '11AM-1PM', 'React (Props, useEffect, API Call, Routing)', 'Learned useEffect hook syntax\r\nUnderstood component lifecycle:\r\nMount\r\nUpdate\r\nUnmount\r\nImplemented:\r\nuseEffect with empty dependency array\r\nuseEffect with dependencies\r\nUsed useEffect for initial data loading\r\nAvoided infinite loops', NULL, NULL, NULL, 'Jayshree'),
