(1446, '4196', '2025-12-16', '4PM-6PM', 'React (Props, useEffect, API Call, Routing)', 'Installed react-router-dom\r\nCreated routes using:\r\n<BrowserRouter>\r\n<Routes>\r\n<Route>\r\nCreated pages:\r\nHome\r\nAbout\r\nDashboard / Products\r\nUsed <Link> and <NavLink> for navigation\r\nTested navigation without page reload', NULL, NULL, NULL, 'Jayshree'),
(1447, '4196', '2025-12-17', '9AM-11AM', '(Forms, Controlled Components, Context API).', 'Learned how forms work in React\r\nImplemented controlled components using useState\r\nHandled input fields:\r\nText\r\nEmail\r\nPassword\r\nManaged form submission using onSubmit\r\nAdded basic validation (required fields)\r\nUnderstood difference between controlled vs uncontrolled components', NULL, NULL, NULL, 'Jayshree'),
(1448, '4196', '2025-12-17', '11AM-1PM', '(Forms, Controlled Components, Context API).', 'Created multi-field forms (registration / login)\r\nHandled multiple inputs using single state object\r\nImplemented handleChange method\r\nReset form after submission\r\nDisplayed form data on UI for testing\r\nPracticed reusable form components', NULL, NULL, NULL, 'Jayshree'),
