(1471, '4196', '2025-12-22', '9AM-11AM', 'JWT Authentication with Backend ', 'Understood JWT authentication flow:\r\n\r\nUser Login ? Server validates ? JWT token generated\r\n\r\nClient stores token ? Sends token in headers\r\n\r\nAdded JWT dependencies in Spring Boot\r\n\r\nCreated:\r\n\r\nAuthController\r\n\r\nLogin request & response DTO\r\n\r\nConfigured secret key and token expiry\r\n\r\nGenerated JWT on successful login', NULL, NULL, NULL, 'Jayshree'),
(1472, '4196', '2025-12-22', '11AM-1PM', 'JWT Authentication with Backend', 'Configured Spring Security\r\n\r\nCreated JWT filter to:\r\n\r\nIntercept requests\r\n\r\nValidate token\r\n\r\nSet authentication context\r\n\r\nSecured APIs:\r\n\r\nPublic ? login, register\r\n\r\nProtected ? dashboard, products, orders\r\n\r\nDisabled CSRF for REST APIs\r\n\r\nTested protected endpoints using Postman', NULL, NULL, NULL, 'Jayshree'),
(1473, '4196', '2025-12-22', '2PM-4PM', 'JWT Authentication with Backend', 'Called login API from React\r\n\r\nStored JWT token in localStorage\r\n\r\nSent token in API headers:\r\n\r\nAuthorization: Bearer <token>\r\n\r\nProtected frontend routes based on token\r\n\r\nHandled token expiry and logout', NULL, NULL, NULL, 'Jayshree'),
